from functools import lru_cache
from pathlib import Path

from pydantic_settings import BaseSettings, SettingsConfigDict


class Settings(BaseSettings):
    model_config = SettingsConfigDict(env_file=".env", env_file_encoding="utf-8", extra="ignore")
    api_host: str = "0.0.0.0"
    api_port: int = 8000
    database_url: str = "sqlite:///./data/acronyms.db"
    team_id: str = "default"
    upload_dir: str = "./data/uploads"
    nlp_url: str = "http://127.0.0.1:8001"
    use_mock_nlp: bool = False

    # LLM
    llm_provider: str = ""

    # OpenAI-compatible endpoint (Bedrock Mantle)
    openai_api_key: str = "https://bedrock-mantle.us-east-1.api.aws/v1"
    openai_base_url: str = "bedrock-api-key-"
    openai_model: str = "gpt-4o-mini"

    # Bedrock Mantle
    bedrock_endpoint: str = "https://bedrock-mantle.us-east-1.api.aws/v1"
    bedrock_api_key: str = "bedrock-api-key-"
    bedrock_model_id: str = "gpt-4o-mini"


@lru_cache
def get_settings() -> Settings:
    settings = Settings()
    Path(settings.upload_dir).mkdir(parents=True, exist_ok=True)
    db_path = settings.database_url.replace("sqlite:///", "")
    if db_path.startswith("./"):
        Path(db_path).parent.mkdir(parents=True, exist_ok=True)
    return settings
